INSERT INTO `hx_activity` VALUES (1,'校园环保志愿行','清理校园死角，共建美丽校园','https://images.unsplash.com/photo-1550989460-0adf9ea622e2?q=80&w=600&auto=format&fit=crop','<p>本次活动旨在组织同学们对校园内的卫生死角进行清理，包括操场角落、教学楼后方等。请大家自带手套，学校提供垃圾袋和清理工具。让我们一起行动起来，为美丽的校园环境贡献一份力量！</p>','2026-01-22 23:32:23','2026-01-21 01:32:23','学校操场集合',50,'0','2026-01-18 23:32:23',1,'admin',13,'0','admin','2026-01-18 23:32:23','admin','2026-01-20 19:14:31','热门活动',NULL),(2,'敬老院爱心慰问','走进敬老院，温暖老人心','https://images.unsplash.com/photo-1516307365426-bea591f05011?q=80&w=600&auto=format&fit=crop','<p>周末我们将前往市郊的“夕阳红”敬老院进行慰问演出和志愿服务。活动内容包括陪老人聊天、打扫卫生以及简单的文艺表演。欢迎有才艺的同学积极报名！</p>','2026-01-13 23:32:23','2026-01-29 03:32:23','夕阳红敬老院',30,'1','2026-01-08 23:32:23',1,'admin',30,'0','admin','2026-01-08 23:32:23','admin','2026-01-20 19:14:31','已结束活动',NULL),(3,'社区图书整理小帮手','协助社区图书馆整理书籍','https://images.unsplash.com/photo-1524995997946-a1c2e315a42f?q=80&w=600&auto=format&fit=crop','<p>社区图书馆近期新进了一批图书，急需志愿者帮忙分类、上架和贴标签。这是一个接触书籍、服务社区的好机会，工作相对轻松，但需要细心和耐心。</p>','2026-01-07 23:32:23','2026-01-31 02:32:23','幸福社区图书馆',10,'1','2026-01-18 23:32:23',1,'admin',5,'0','admin','2026-01-18 23:32:23','admin','2026-01-20 19:14:31','招募中',NULL),(4,'义诊服务进万家','配合校医院开展社区义诊','https://images.unsplash.com/photo-1576091160399-112ba8d25d1d?q=80&w=600&auto=format&fit=crop','<p>配合校医院的医生团队，前往周边小区开展义诊活动。志愿者主要负责维持秩序、引导居民、分发健康宣传手册等工作。医学相关专业同学优先。</p>','2026-01-21 00:00:00','2026-01-29 03:32:23','阳光花园小区广场',20,'0','2026-01-18 23:33:39',1,'admin',1,'0','admin','2026-01-18 23:32:23','admin','2026-01-20 19:14:31','草稿状态',NULL);
