  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '解答内容',
  `video_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '视频链接',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '状态（0草稿 1发布 2下架）',
  `sort` int DEFAULT '0' COMMENT '排序值',
  `publish_time` datetime DEFAULT NULL COMMENT '发布时间',
  `publish_user_id` bigint DEFAULT NULL COMMENT '发布人ID',
  `publish_user_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '发布人名称',
