INSERT INTO `hx_qa` VALUES (1,'目前面向高校学生的主要资助项目有哪些？','国家奖学金、国家励志奖学金、国家助学金、国家助学贷款。',NULL,'1',0,'2026-01-19 16:01:30',1,'admin',0,'0','admin','2026-01-19 16:01:30',NULL,NULL,''),(2,'国家励志奖学金资助对象和标准是什么？','奖励品学兼优的家庭经济困难本专科生（二年级及以上），每生每年6000元。颁发教育部统一印制的荣誉证书，并记入学生的学籍档案。',NULL,'1',0,'2026-01-19 16:01:40',1,'admin',0,'0','admin','2026-01-19 16:01:40',NULL,NULL,''),(3,'国家助学金资助对象和标准是什么？','家庭经济困难学生入学后可申请国家助学金，解决在校期间的生活费，平均每生每年3700元。学生于每年9月登录江苏学生资助微信公众号，通过江苏省学生资助申请平台提出申请，每学年秋季评定。',NULL,'1',0,'2026-01-19 16:01:48',1,'admin',0,'0','admin','2026-01-19 16:01:48',NULL,NULL,''),(4,'国家助学贷款资助对象和标准是什么？','家庭经济困难生可申请办理国家助学贷款，解决学费，住宿费和生活费。每生每年最高不超过两万元，在校期间利息由国家承担，还息期限原则上按学制加15年确定，最长不超过22年。',NULL,'1',0,'2026-01-19 16:01:59',1,'admin',0,'0','admin','2026-01-19 16:01:59',NULL,NULL,''),(5,'国家助学贷款的方式有哪些 ？','国家助学贷款包括生源地信用助学贷款与校园地信用助学贷款。江苏省主要以生源地信用助学贷款为主。家庭经济困难生可向户籍所在县市、区的学生资助管理机构咨询办理。没有办理生源地信用助学贷款的学生，可向高校学生资助部门咨询办理校园地国家助学贷款。',NULL,'1',0,'2026-01-19 16:02:08',1,'admin',0,'0','admin','2026-01-19 16:02:08',NULL,NULL,''),(6,'家庭经济困难学生认定的具体流程是什么？需要提交哪些证明材料？','认定的具体流流程通常：学生申请→学校审核→公示认定。\n学生申请：学生需提交《家庭经济困难学生认定申请表》，并可自愿补充以下材料：建档立卡、低保、特困救助供养、孤儿、残疾等身份证明复印件；家庭突发变故（如重大疾病、自然灾害）的医疗证明、村委会/居委会开具的困难说明等。\n学校审核：通过班级民主评议、辅导员家访、大数据分析等方式核实，分为一般困难、困难、特别困难三级。\n公示认定：公示，如有异议可申诉。\n',NULL,'1',0,'2026-01-19 16:02:20',1,'admin',0,'0','admin','2026-01-19 16:02:20',NULL,NULL,''),(7,'学生未申请助学金，若家庭突发变故导致经济困难，能否中途申请资助？需要提供哪些补充材料？','若学生家庭在学期中途发生重大变故（如自然灾害、家人突发重大疾病等）导致经济困难，通常可以申请困难补助或调整原有的困难等级。一般每年的春季增补，秋季重新认定。',NULL,'1',0,'2026-01-19 16:02:36',1,'admin',0,'0','admin','2026-01-19 16:02:36','admin','2026-01-19 18:21:25',''),(8,'奖学金（如国家奖学金、励志奖学金等）的评选标准中，成绩、综合素质、家庭经济状况分别占多大比重？','国家奖学金：以成绩和科研成果为核心，学习成绩与综合测评成绩排名一般应位于本班级前10%，同时考察竞赛获奖、社会服务等综合素质，不限制家庭经济状况。\n国家励志奖学金：学习成绩要求在班级排名前30%或综合测评成绩必须达到班级前45%，必须为上一年度认定为家庭经济困难学生。',NULL,'1',0,'2026-01-19 16:02:48',1,'admin',0,'0','admin','2026-01-19 16:02:48','admin','2026-01-19 16:03:07',''),(9,'申请校内勤工助学岗位需要满足什么条件？薪酬标准如何确定？','家庭经济困难生在学有余力的前提下，可以在学校组织下利用课余时间参加勤工助学活动。学生参加勤工助学原则上每周不超过8小时，每月不超过40小时。',NULL,'1',0,'2026-01-19 16:03:18',1,'admin',0,'0','admin','2026-01-19 16:03:18',NULL,NULL,''),(10,'获得各类资助的学生应当履行哪些基本义务？','（1）诚信申报义务：所有申请资助的学生，必须如实、准确、完整地填报本人及家庭的经济状况，提交真实有效的证明材料。不得有任何隐瞒实际收入、资产或提供虚假信息、伪造证明文件的行为。\n（2）勤勉向学义务：资助旨在支持学生顺利完成学业。获得者须刻苦学习，积极进取，努力达到所在培养阶段的基本学业要求。例如，申请国家励志奖学金者，其学习成绩须达到优秀标准。\n（3）合理使用义务：资助款项应严格用于与学业相关的必要支出，如缴纳学杂费、住宿费，以及保障基本生活学习所需。严禁将其用于高消费或其他不当用途。\n（4）社会回馈义务：部分资助项目（如国家励志奖学金、国家助学金）设有明确要求，获得者需按学校规定参与一定时长或形式的公益活动，如志愿服务、社区建设、学业帮扶等，以践行社会责任，培养感恩意识。\n',NULL,'1',0,'2026-01-19 16:03:27',1,'admin',0,'0','admin','2026-01-19 16:03:27',NULL,NULL,'');
/*!40000 ALTER TABLE `hx_qa` ENABLE KEYS */;
UNLOCK TABLES;

