INSERT INTO `hx_story` VALUES (1,'第一次当志愿者的感悟','那是初秋的一个下午，我第一次穿上红马甲...','https://images.unsplash.com/photo-1469571486292-0ba58a3f068b?q=80&w=600&auto=format&fit=crop','<p>	<strong>那是初秋的一个下午，我第一次穿上红马甲</strong>，站在路口协助交警维持交通秩序。起初我有些害羞，不敢大声说话，但看到一位老奶奶过马路不便时，我鼓起勇气走上前去搀扶。那一刻，她手中的温度传到了我的心里。虽然站了两个小时很累，但听到行人的每一声“谢谢”，我都觉得无比满足。志愿服务不仅仅是付出，更是一种收获，它让我感受到了人与人之间最纯粹的善意。</p><p><img src=\"http://59.110.229.252:8080/profile/upload/2026/01/19/image_20260119122218A004.png\"></p><p>	那是初秋的一个下午，我第一次穿上红马甲，站在路口协助交警维持交通秩序。起初我有些害羞，不敢大声说话，但看到一位老奶奶过马路不便时，我鼓起勇气走上前去搀扶。那一刻，她手中的温度传到了我的心里。虽然站了两个小时很累，但听到行人的每一声“谢谢”，我都觉得无比满足。志愿服务不仅仅是付出，更是一种收获，它让我感受到了人与人之间最纯粹的善意。</p>','1',1,'2026-01-16 23:32:23',1,'admin',201,'0','admin','2026-01-18 23:32:23','admin','2026-01-19 13:16:56','精选故事',23),(2,'雨中送伞的小确幸','一场突如其来的大雨，一次温暖的传递','https://images.unsplash.com/photo-1515694346937-94d85e41e6f0?q=80&w=600&auto=format&fit=crop','今天放学突然下起了倾盆大雨，我没带伞，正站在教学楼门口发愁。这时，一位陌生的同学走过来，微笑着问我要去哪里，说可以顺路送我一程。我们就这样撑着一把伞走到了宿舍楼下。虽然我的肩膀湿了一点，但心里却是暖暖的。这件事让我明白，善意是可以传递的，下一次，我也要做那个为别人撑伞的人。','1',2,'2026-01-13 23:32:23',1,'admin',93,'0','admin','2026-01-18 23:32:23','admin','2026-01-18 23:32:23','日常点滴',12),(3,'敬老院里的歌声','用歌声传递快乐，陪伴是最长情的告白','https://images.unsplash.com/photo-1516307365426-bea591f05011?q=80&w=600&auto=format&fit=crop','上周的敬老院之行让我印象深刻。我和几个同学准备了几首老歌，当我们唱起《东方红》时，几位爷爷奶奶也跟着哼唱起来，脸上洋溢着孩子般的笑容。演出结束后，一位奶奶拉着我的手说了好久的话，她说她想起了自己的孙女。那一刻我意识到，对于老人们来说，物质的馈赠或许重要，但真诚的陪伴和倾听才是他们最渴望的。','1',3,'2026-01-08 23:32:23',1,'admin',230,'0','admin','2026-01-18 23:32:23','admin','2026-01-18 23:32:23','活动感悟',45),(4,'图书馆的“神秘”角落','在整理图书时发现的惊喜','https://images.unsplash.com/photo-1507842217121-9e96e4765949?q=80&w=600&auto=format&fit=crop','作为图书馆志愿者，我负责整理最角落的文学书架。在整理过程中，我发现很多书里夹着以前同学写的便签，有的是读书心得，有的是对未来的期许，还有互相鼓励的话语。这些跨越时空的文字交流让我觉得图书馆不仅是藏书的地方，更是思想碰撞的火花之地。我把这些便签小心翼翼地收好，也许未来某一天，它们会成为学校珍贵的记忆档案。','1',4,'2026-01-19 00:15:58',1,'admin',1,'0','admin','2026-01-18 23:32:23','admin','2026-01-19 00:15:58','草稿故事',0);
/*!40000 ALTER TABLE `hx_story` ENABLE KEYS */;
UNLOCK TABLES;

