rofile/updatePwd','192.168.31.75','内网IP','{}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2026-01-16 16:10:23',241),(284,'部门管理',2,'com.ruoyi.web.controller.system.SysDeptController.edit()','PUT',1,'admin','管理员','/system/dept','127.0.0.1','内网IP','{\"ancestors\":\"0,100\",\"children\":[],\"deptId\":200,\"deptName\":\"26届\",\"leader\":\"卢杨\",\"orderNum\":3,\"params\":{},\"parentId\":100,\"parentName\":\"扬州职业技术大学信息工程学院\",\"status\":\"0\"}','{\"msg\":\"修改部门\'26届\'失败，部门名称已存在\",\"code\":500}',0,NULL,'2026-01-16 16:34:01',40),(285,'菜单管理',2,'com.ruoyi.web.controller.system.SysMenuController.edit()','PUT',1,'admin','管理员','/system/menu','127.0.0.1','内网IP','{\"children\":[],\"component\":\"monitor/server/index\",\"createTime\":\"2025-11-14 14:52:55\",\"icon\":\"server\",\"isCache\":\"0\",\"isFrame\":\"1\",\"menuId\":112,\"menuName\":\"服务监控\",\"menuType\":\"C\",\"orderNum\":4,\"params\":{},\"parentId\":2,\"path\":\"server\",\"perms\":\"monitor:server:list\",\"query\":\"\",\"routeName\":\"\",\"status\":\"0\",\"updateBy\":\"admin\",\"visible\":\"0\"}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2026-01-17 15:01:24',121),(286,'问答管理',2,'com.ruoyi.web.controller.hx.HxQaController.edit()','PUT',1,'admin','管理员','/hx/qa','117.94.253.130','XX XX','{\"content\":\"<p class=\\\"ql-align-justify\\\">医护人员提着精心挑选月饼，轻轻放在每位患者手中，<span style=\\\"color: rgb(0, 0, 0);\\\">贴心叮嘱：“莲蓉馅不甜，长辈们吃着正好。”赵大爷接过月饼，没说话，只是望着月亮出神——那月光，大概也正照着他远方的儿女吧。护士搬来椅子，坐在他身边：“大爷，今晚我们陪您一起看月亮，这儿也是您的家。”</span></p><p class=\\\"ql-align-justify\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">另一边，李阿姨正笑着打电话：“妈这儿也有月饼吃，豆沙的，等你回来我们再吃一次……”几句话，把整个病房都说暖了。这个夜晚，病痛暂时退居其次，人与人之间的靠近，成了最好的药。</span></p><p class=\\\"ql-align-justify\\\"><br></p><p class=\\\"ql-align-justify\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">重阳节前后，桂花开了，香气若有似无地飘进病房。医护人员端来刚蒸好的重阳糕，细心照顾着每位老人的不同需要——扶一把、吹一吹、陪一会儿。有老人吃着吃着就红了眼眶：“这味道，像我母亲从前做的……”</span></p><p class=\\\"ql-align-justify\\\"><span style=\\\"color: rgb(0, 0, 0);\\\">更让人动容的是做桂花画的时候。李爷爷手抖得厉害，却坚持要自己撒花瓣。当金色的桂花落在纸上，他笑得像个孩子：“这辈子第一次做这么风雅的事。”陈奶奶把完成的作品轻轻贴在胸前，闭眼闻着：“真香啊，跟我家院里那棵老桂花树一个味道。”那一刻，病房不再是病房，倒像是个老友相聚的温暖客厅。</span></p>\",\"createBy\":\"admin\",\"createTime\":\"2026-01-15 11:53:50\",\"delFlag\":\"0\",\"params\":{},\"publishTime\":\"2026-01-15 11:53:50\",\"publishUserId\":1,\"publishUserName\":\"admin\",\"qaId\":1,\"remark\":\"\",\"sort\":0,\"status\":\"1\",\"title\":\"测试修改\",\"updateBy\":\"admin\",\"updateTime\":\"2026-01-17 17:17:59\",\"videoUrl\":\"https://alimov2.a.kwimgs.com/upic/2023/09/21/17/BMjAyMzA5MjExNzAxMzFfMzgyMzQ3MjQ1XzExMzI1MzA2MDIyNl8wXzM=_b_B3efccdf8224f2228d5ad7309db80f7ef.mp4?clientCacheKey=3x7u2m2iqr2ardu_b.mp4&tt=b&di=78e498d6&bp=13414\",\"viewCount\":150}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2026-01-17 17:17:59',239),(287,'菜单管理',2,'com.ruoyi.web.controller.system.SysMenuController.edit()','PUT',1,'admin','管理员','/system/menu','127.0.0.1','内网IP','{\"children\":[],\"component\":\"hx/file/index\",\"createTime\":\"2026-01-17 18:05:06\",\"icon\":\"tab\",\"isCache\":\"0\",\"isFrame\":\"1\",\"menuId\":1205,\"menuName\":\"文件管理\",\"menuType\":\"C\",\"orderNum\":6,\"params\":{},\"parentId\":1200,\"path\":\"file\",\"perms\":\"hx:file:list\",\"query\":\"\",\"routeName\":\"\",\"status\":\"0\",\"updateBy\":\"admin\",\"visible\":\"0\"}','{\"msg\":\"操作成功\",\"code\":200}',0,NULL,'2026-01-17 18:06:06',109),(288,'文件管理',1,'com.ruoyi.web.controller.hx.HxFileController.uploadFile()','POST',1,'admin','管理员','/hx/file/upload','127.0.0.1','内网IP','{\"businessField\":\"coverUrl\",\"fileCategory\":\"cover\",\"businessType\":\"story\"}',NULL,1,'文件上传失败','2026-01-17 18:06:17',149),(289,'文件管理',1,'com.ruoyi.web.controller.hx.HxFileController.uploadFile()','POST',1,'admin','管理员','/hx/file/upload','127.0.0.1','内网IP','{\"businessField\":\"coverUrl\",\"fileCategory\":\"cover\",\"businessType\":\"story\"}',NULL,1,'文件上传失败','2026-01-17 18:06:20',75),(290,'文件管理',1,'com.ruoyi.web.controller.hx.HxFileController.uploadFile()','POST',1,'admin','管理员','/hx/file/upload','127.0.0.1','内网IP','{\"businessField\":\"coverUrl\"